#!/bin/bash\n\n# FormCritic Lambda Deployment Script\n# Run this with AWS credentials that have Lambda, IAM, and CloudWatch permissions\n\nset -e\n\necho \"🚀 Deploying FormCritic Lambda Function...\"\n\n# Configuration\nFUNCTION_NAME=\"form-critic-analyzer\"\nREGION=\"us-east-1\"  # Change if needed\nRUNTIME=\"nodejs18.x\"\nTIMEOUT=\"60\"\nMEMORY=\"1024\"\nVERSION=$(date +%Y%m%d_%H%M%S)\n\n# Step 1: Create IAM Role (if not exists)\necho \"📋 Setting up IAM role...\"\nROLE_NAME=\"form-critic-lambda-role\"\nTRUST_POLICY='{\n  \"Version\": \"2012-10-17\",\n  \"Statement\": [\n    {\n      \"Effect\": \"Allow\",\n      \"Principal\": {\n        \"Service\": \"lambda.amazonaws.com\"\n      },\n      \"Action\": \"sts:AssumeRole\"\n    }\n  ]\n}'\n\nROLE_ARN=$(aws iam get-role --role-name $ROLE_NAME --region $REGION --query 'Role.Arn' --output text 2>/dev/null || echo \"\")\n\nif [ -z \"$ROLE_ARN\" ]; then\n  echo \"  Creating role: $ROLE_NAME\"\n  ROLE_ARN=$(aws iam create-role \\\n    --role-name $ROLE_NAME \\\n    --assume-role-policy-document \"$TRUST_POLICY\" \\\n    --region $REGION \\\n    --query 'Role.Arn' \\\n    --output text)\n  echo \"  ✅ Role created: $ROLE_ARN\"\n  \n  # Attach basic Lambda execution policy\n  aws iam attach-role-policy \\\n    --role-name $ROLE_NAME \\\n    --policy-arn arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole \\\n    --region $REGION\n  \n  sleep 10  # Wait for role to propagate\nelse\n  echo \"  ✅ Role exists: $ROLE_ARN\"\nfi\n\n# Step 2: Build the Lambda package\necho \"🔨 Building Lambda package...\"\ncd lambda\nnpm install\nnpm run build\ncd ..\n\n# Step 3: Create Lambda function or update existing\necho \"📦 Creating/updating Lambda function...\"\n\n# Create a temporary zip for deployment\nmkdir -p /tmp/lambda-deploy\ncp -r lambda/dist /tmp/lambda-deploy/\ncp -r lambda/node_modules /tmp/lambda-deploy/\ncd /tmp/lambda-deploy\n\n# Create zip\nzip -r /tmp/form-critic-lambda.zip dist/ node_modules/ > /dev/null 2>&1 || {\n  # Fallback if zip not available\n  cd dist && tar -czf /tmp/form-critic-lambda.tar.gz * && cd /tmp\n  echo \"  Note: Created tar.gz instead of zip. Please upload /tmp/form-critic-lambda.tar.gz manually to Lambda.\"\n  exit 1\n}\n\necho \"  Package size: $(du -h /tmp/form-critic-lambda.zip | cut -f1)\"\n\n# Check if function exists\nFUNCTION_EXISTS=$(aws lambda list-functions --region $REGION --query \"Functions[?FunctionName=='$FUNCTION_NAME'].FunctionName\" --output text 2>/dev/null || echo \"\")\n\nif [ -z \"$FUNCTION_EXISTS\" ]; then\n  echo \"  Creating new Lambda function...\"\n  aws lambda create-function \\\n    --function-name $FUNCTION_NAME \\\n    --runtime $RUNTIME \\\n    --role $ROLE_ARN \\\n    --handler dist/index.handler \\\n    --timeout $TIMEOUT \\\n    --memory-size $MEMORY \\\n    --zip-file fileb:///tmp/form-critic-lambda.zip \\\n    --region $REGION \\\n    --environment \"Variables={ANTHROPIC_API_KEY=$ANTHROPIC_API_KEY}\" \\\n    --architectures x86_64\n  echo \"  ✅ Function created\"\nelse\n  echo \"  Updating existing Lambda function...\"\n  aws lambda update-function-code \\\n    --function-name $FUNCTION_NAME \\\n    --zip-file fileb:///tmp/form-critic-lambda.zip \\\n    --region $REGION\n  echo \"  ✅ Function updated\"\nfi\n\n# Step 4: Set environment variables\necho \"🔑 Setting environment variables...\"\nif [ -z \"$ANTHROPIC_API_KEY\" ]; then\n  echo \"  ⚠️  ANTHROPIC_API_KEY not set in environment\"\n  echo \"  Please set it manually in AWS Lambda console or run:\"\n  echo \"  aws lambda update-function-configuration --function-name $FUNCTION_NAME --environment 'Variables={ANTHROPIC_API_KEY=sk-ant-...}'\"\nelse\n  aws lambda update-function-configuration \\\n    --function-name $FUNCTION_NAME \\\n    --environment \"Variables={ANTHROPIC_API_KEY=$ANTHROPIC_API_KEY}\" \\\n    --region $REGION > /dev/null\n  echo \"  ✅ ANTHROPIC_API_KEY set\"\nfi\n\n# Step 5: Create/update Function URL\necho \"🌐 Setting up Function URL...\"\nFUNCTION_URL=$(aws lambda get-function-url-config \\\n  --function-name $FUNCTION_NAME \\\n  --region $REGION \\\n  --query 'FunctionUrl' \\\n  --output text 2>/dev/null || echo \"\")\n\nif [ -z \"$FUNCTION_URL\" ]; then\n  echo \"  Creating Function URL...\"\n  FUNCTION_URL=$(aws lambda create-function-url-config \\\n    --function-name $FUNCTION_NAME \\\n    --auth-type NONE \\\n    --cors '{\n      \"AllowOrigins\": [\"*\"],\n      \"AllowMethods\": [\"POST\"],\n      \"AllowHeaders\": [\"Content-Type\"],\n      \"MaxAge\": 86400\n    }' \\\n    --region $REGION \\\n    --query 'FunctionUrl' \\\n    --output text)\n  echo \"  ✅ Function URL created\"\nelse\n  echo \"  ✅ Function URL exists\"\nfi\n\necho \"\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"✅ Lambda deployment complete!\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"\"\necho \"📌 Function Details:\"\necho \"   Name: $FUNCTION_NAME\"\necho \"   Region: $REGION\"\necho \"   Runtime: $RUNTIME\"\necho \"   Memory: ${MEMORY}MB\"\necho \"   Timeout: ${TIMEOUT}s\"\necho \"\"\necho \"🔗 Function URL:\"\necho \"   $FUNCTION_URL\"\necho \"\"\necho \"📝 Next Steps:\"\necho \"   1. Copy the Function URL above\"\necho \"   2. Update src/utils/aws.ts with your Function URL\"\necho \"   3. Update .env.local:\"\necho \"      EXPO_PUBLIC_LAMBDA_ENDPOINT=$FUNCTION_URL\"\necho \"   4. Test locally: npm start\"\necho \"   5. Deploy to TestFlight: eas build --platform ios --profile preview\"\necho \"\"\necho \"🧪 Test the Lambda:\"\necho \"   curl -X POST $FUNCTION_URL \\\\\"\necho \"     -H 'Content-Type: application/json' \\\\\"\necho \"     -d '{\\\"video\\\":\\\"base64_video_data\\\",\\\"videoSize\\\":1000,\\\"timestamp\\\":\\\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\\\"}'\"\necho \"\"\necho \"📊 Monitor logs:\"\necho \"   aws logs tail /aws/lambda/$FUNCTION_NAME --follow\"\necho \"\"\n"
